'use client';

import useSWR from 'swr';
import { motion } from 'framer-motion';
import { useEffect, useRef, useState } from 'react';
import * as THREE from 'three';

const fetcher = (url: string) => fetch(url).then((res) => res.json());

// Conflict Heatmap Component
function ConflictHeatmap({ conflicts }: any) {
  const containerRef = useRef<HTMLDivElement>(null);
    useEffect(() => {
        if (!containerRef.current || conflicts.length === 0) return;
            const scene = new THREE.Scene();
                const camera = new THREE.PerspectiveCamera(75, containerRef.current.clientWidth / containerRef.current.clientHeight, 0.1, 10000);
                    const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: true });
                        renderer.setSize(containerRef.current.clientWidth, containerRef.current.clientHeight);
                            renderer.setClearColor(0x000000, 0);
                                containerRef.current.appendChild(renderer.domElement);
                                    camera.position.z = 2;

                                        const geometry = new THREE.BufferGeometry();
                                            const positions: number[] = [];
                                                const colors: number[] = [];
                                                    const sizes: number[] = [];

                                                        conflicts.forEach((conflict: any) => {
                                                              const x = ((conflict.lng + 180) / 360) * 2 - 1;
                                                                    const y = ((90 - conflict.lat) / 180) * 2 - 1;
                                                                          const z = (Math.random() - 0.5) * 0.1;
                                                                                positions.push(x, y, z);
                                                                                      const red = conflict.intensity;
                                                                                            const green = (1 - conflict.intensity) * 0.5;
                                                                                                  colors.push(red, green, 0.2);
                                                                                                        sizes.push(conflict.intensity * 30 + 10);
                                                                                                            });
                                                                                                            
                                                                                                                geometry.setAttribute('position', new THREE.BufferAttribute(new Float32Array(positions), 3));
                                                                                                                    geometry.setAttribute('color', new THREE.BufferAttribute(new Float32Array(colors), 3));
                                                                                                                        geometry.setAttribute('size', new THREE.BufferAttribute(new Float32Array(sizes), 1));
                                                                                                                        
                                                                                                                            const material = new THREE.PointsMaterial({ size: 1, sizeAttenuation: true, vertexColors: true, transparent: true, opacity: 0.8 });
                                                                                                                                const particles = new THREE.Points(geometry, material);
                                                                                                                                    scene.add(particles);
                                                                                                                                    
                                                                                                                                        const animate = () => {
                                                                                                                                              requestAnimationFrame(animate);
                                                                                                                                                    particles.rotation.x += 0.00005;
                                                                                                                                                          particles.rotation.y += 0.00003;
                                                                                                                                                                renderer.render(scene, camera);
                                                                                                                                                                    };
                                                                                                                                                                        animate();
                                                                                                                                                                            return () => { containerRef.current?.removeChild(renderer.domElement); };
                                                                                                                                                                              }, [conflicts]);
                                                                                                                                                                              
                                                                                                                                                                                return <div ref={containerRef} className="absolute inset-0 w-full h-full opacity-60" />;
                                                                                                                                                                                }
                                                                                                                                                                                
                                                                                                                                                                                // Signal Core Component
                                                                                                                                                                                function SignalCore() {
                                                                                                                                                                                  const { data, isLoading } = useSWR('/api/reports', fetcher, { refreshInterval: 30000 });
                                                                                                                                                                                    const reports = data?.reports || [];
                                                                                                                                                                                    
                                                                                                                                                                                      return (
                                                                                                                                                                                          <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} transition={{ duration: 0.5 }} className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-full max-w-2xl">
                                                                                                                                                                                                <div className="bg-black/50 border-2 border-cyan-500 rounded-lg p-6 backdrop-blur-xl shadow-2xl">
                                                                                                                                                                                                        <h2 className="text-xl font-mono text-cyan-400 flex items-center mb-6">
                                                                                                                                                                                                                  <span className="w-2 h-2 bg-cyan-500 rounded-full mr-2 animate-pulse" />
                                                                                                                                                                                                                            SIGNAL CORE
                                                                                                                                                                                                                                    </h2>
                                                                                                                                                                                                                                            <div className="space-y-3 max-h-96 overflow-y-auto">
                                                                                                                                                                                                                                                      {isLoading ? (
                                                                                                                                                                                                                                                                  <div className="text-cyan-400 text-xs font-mono">Loading signals...</div>
                                                                                                                                                                                                                                                                            ) : (
                                                                                                                                                                                                                                                                                        reports.map((report: any) => (
                                                                                                                                                                                                                                                                                                      <motion.div key={report.id} initial={{ opacity: 0, x: -10 }} animate={{ opacity: 1, x: 0 }} className="p-3 border border-cyan-500/30 rounded bg-cyan-500/5 hover:border-cyan-400 hover:bg-cyan-500/10 transition-all cursor-pointer">
                                                                                                                                                                                                                                                                                                                      <div className="flex justify-between items-start mb-1">
                                                                                                                                                                                                                                                                                                                                        <div className="flex items-center gap-2">
                                                                                                                                                                                                                                                                                                                                                            <span className={`text-xs font-bold ${report.priority === 'CRITICAL' ? 'text-red-500' : report.priority === 'HIGH' ? 'text-orange-500' : 'text-yellow-500'}`}>{report.priority}</span>
                                                                                                                                                                                                                                                                                                                                                                                <span className="text-xs text-gray-400">{report.sector}</span>
                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                    <span className="text-xs text-gray-500">{new Date(report.timestamp).toLocaleTimeString()}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="text-sm font-mono text-white mb-1">{report.title}</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="text-xs text-gray-400 font-mono line-clamp-2">{report.summary}</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </motion.div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ))
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="mt-4 pt-4 border-t border-cyan-500/30 text-xs text-gray-500 font-mono">Last update: {new Date().toLocaleTimeString()}</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </motion.div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // Bridgepath Component
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    function Bridgepath() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const { data, isLoading } = useSWR('/api/bridgepath', fetcher, { refreshInterval: 45000 });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const companies = data?.companies || [];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <motion.div initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} transition={{ duration: 0.6 }} className="absolute top-4 right-4 w-96 bg-black/40 border border-orange-500 rounded-lg p-4 backdrop-blur-md max-h-96 overflow-y-auto">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="text-orange-400 text-xs font-mono mb-3">BRIDGEPATH • PRE-IPO TRACKER</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {isLoading ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="text-orange-400 text-xs font-mono">Loading pipeline...</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ) : (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="space-y-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {companies.map((company: any) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <motion.div key={company.id} initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} className="p-2 border border-orange-500/30 rounded text-xs font-mono hover:border-orange-400 transition-all cursor-pointer">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="flex justify-between items-start mb-1">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <span className="text-white font-bold">{company.company}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <span className={`text-xs px-2 py-1 rounded ${company.signal === 'STRONG' ? 'bg-green-500/20 text-green-400' : 'bg-yellow-500/20 text-yellow-400'}`}>{company.signal}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="flex justify-between text-gray-400 mb-1">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <span>{company.valuation}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <span>{company.stage}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="flex items-center gap-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="flex-1 bg-black/50 rounded h-1">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className={`h-full rounded ${company.ipo_probability >= 0.8 ? 'bg-green-500' : company.ipo_probability >= 0.6 ? 'bg-yellow-500' : 'bg-orange-500'}`} style={{ width: `${company.ipo_probability * 100}%` }} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <span className="text-gray-500">{Math.round(company.ipo_probability * 100)}%</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="text-gray-500 text-xs mt-1">{company.timeline}</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </motion.div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </motion.div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // Options Flow Component
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    function OptionsFlow() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const { data, isLoading } = useSWR('/api/options', fetcher, { refreshInterval: 15000 });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const options = data?.options || [];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.6 }} className="absolute bottom-0 left-0 right-0 h-16 bg-gradient-to-r from-black via-black to-transparent border-t border-purple-500 backdrop-blur-md overflow-hidden">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="h-full flex items-center px-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="text-purple-400 text-xs font-mono whitespace-nowrap mr-4">OPTIONS FLOW:</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {isLoading ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="text-purple-400 text-xs font-mono">Loading...</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      ) : (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="flex gap-6 animate-scroll overflow-x-auto pb-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {[...options, ...options].map((option: any, idx: number) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div key={idx} className="text-xs font-mono whitespace-nowrap flex gap-2 items-center">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <span className="text-white font-bold">{option.ticker}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <span className={`px-2 py-1 rounded ${option.type === 'CALL' ? 'bg-green-500/20 text-green-400' : 'bg-red-500/20 text-red-400'}`}>{option.type}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <span className="text-purple-300">{option.volume}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <span className="text-gray-500">@ {option.strike}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <style jsx>{`@keyframes scroll {0% {transform: translateX(0);} 100% {transform: translateX(-50%);}} .animate-scroll {animation: scroll 30s linear infinite;}`}</style>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </motion.div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Main Intel System
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        export function IntelSystem() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const { data: conflictData } = useSWR('/api/conflicts', fetcher, { refreshInterval: 30000 });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const conflicts = conflictData?.conflicts || [];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <section className="relative w-full h-screen bg-black overflow-hidden">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="absolute inset-0 opacity-5">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <svg width="100%" height="100%">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <defs>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <path d="M 40 0 L 0 0 0 40" fill="none" stroke="cyan" strokeWidth="0.5" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </pattern>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </defs>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <rect width="100%" height="100%" fill="url(#grid)" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </svg>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="absolute top-0 left-1/2 w-96 h-96 bg-cyan-500 rounded-full mix-blend-multiply filter blur-3xl opacity-5 animate-pulse transform -translate-x-1/2 -translate-y-1/2" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <ConflictHeatmap conflicts={conflicts} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <SignalCore />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <Bridgepath />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <OptionsFlow />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 1 }} className="absolute top-4 left-4 text-xs font-mono text-green-400 flex items-center">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <span className="w-2 h-2 bg-green-500 rounded-full mr-2 animate-pulse" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      SYSTEM ONLINE • {new Date().toLocaleTimeString()}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </motion.div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.3 }} className="absolute top-1/3 left-4 text-sm font-mono text-cyan-400/50 pointer-events-none">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div>▼ INTELLIGENCE SYNTHESIS ACTIVE</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="text-xs mt-1">Multi-domain awareness matrix engaged</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </motion.div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </section>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
